.darma-loader-darma-custom-201 {
  color: var(--loader-color, #9333ea);
height: 15px;
aspect-ratio: 4;
display: grid;
animation: darma-loader-darma-custom-201-l31-0 1s infinite;
}
.darma-loader-darma-custom-201:before,
.darma-loader-darma-custom-201:after {
content: "";
grid-area: 1/1;
--_g: no-repeat radial-gradient(farthest-side,currentColor 94%,#0000);
background:
var(--_g) left,
var(--_g) right;
background-size: 25% 100%;
}
.darma-loader-darma-custom-201:after {
transform: rotate(0) translate(37.5%) rotate(0);
animation: inherit;
animation-name: darma-loader-darma-custom-201-l31-1;
}
@keyframes darma-loader-darma-custom-201-l31-0 {
100% {transform:translate(37.5%)}
}
@keyframes darma-loader-darma-custom-201-l31-1 {
100% {transform:rotate(-.5turn) translate(37.5%) rotate(.5turn)}
}

